// Commit finishes the open entity, buffers the row, and writes it
// through to attached cache views: the entity is populated and pinned
// until the store's Flush makes it durable — reads after writes hit
// immediately, and the caching version gate plus the pin make a raced
// refetch of the pre-write row bounce off. A commit that touched
// Raw() cannot be materialized faithfully and invalidates the key
// instead. A failed Commit rolls the frame back — the entity is
// discarded and the store stays usable.
func (inst *LedgerEntityBuilder) Commit() (err error) {
	err = lowlevel.InEntityLedgerTableCommitEntity(inst.store.dml)
	inst.store.dml.PopMembershipsHighCardRef(inst.pushed) // release Begin's ambient stamps (consumed by the closed attributes)
	if err != nil {
		_ = lowlevel.InEntityLedgerTableRollbackEntity(inst.store.dml) // no-op error when no frame is open
		return
	}
	inst.store.buffered++
	inst.store.dirty[inst.key] = struct{}{}
	if inst.raw {
		inst.store.notifyWrite(inst.key, nil)
	} else {
		ent := inst.ent
		inst.store.notifyWrite(inst.key, &ent)
	}
	return
}

// Rollback abandons the open entity frame without committing it;
// already-buffered rows and the store remain usable.
func (inst *LedgerEntityBuilder) Rollback() (err error) {
	inst.store.dml.PopMembershipsHighCardRef(inst.pushed)
	return lowlevel.InEntityLedgerTableRollbackEntity(inst.store.dml)
}

// IngestOpened buffers one whole entity per row carrying only the
// Opened component, all stamped with ts — rows ship on the next Flush,
// like every write. Keys must be distinct within one call (rows
// share ts, so duplicates would tie on Order): a duplicate returns
// recordstore.ErrDuplicateIngestKey. On any error the rows buffered
// so far remain buffered — Flush ships them, DiscardPending drops
// them.
func (inst *LedgerStore) IngestOpened(ts time.Time, rows []Opened) (err error) {
	seen := make(map[string]struct{}, len(rows))
	for i := range rows {
		if _, dup := seen[rows[i].ID]; dup {
			err = eh.Errorf("ingest opened row %d: %w: key %v", i, recordstore.ErrDuplicateIngestKey, rows[i].ID)
			return
		}
		seen[rows[i].ID] = struct{}{}
		err = inst.Begin(rows[i].ID, ts).AddOpened(rows[i]).Commit()
		if err != nil {
			err = eh.Errorf("ingest opened row %d: %w", i, err)
			return
		}
	}
	return
}

