// Latest returns the newest row for key, tombstone-blind (the raw
// row-level primitive — a deleted key still returns its tombstone
// row; GetLive is the interpreted state-view read). Reads see only
// flushed rows.
func (inst *LedgerStore) Latest(ctx context.Context, key string) (ent *LedgerEntity, found bool, err error) {
	sql := "SELECT * FROM " + LedgerTableName +
		" WHERE " + LedgerColKey + " = " + ledgerKeyLiteral(key) +
		" ORDER BY " + LedgerColOrder + " DESC LIMIT 1" + ledgerArrowOutputSettings
	ents, err := inst.queryEntities(ctx, sql)
	if err != nil || len(ents) == 0 {
		return
	}
	ent = ents[0]
	found = true
	return
}

// Replay iterates the rows for key with the order column >= fromOrder
// in ascending order — the event-replay primitive. A zero fromOrder
// replays everything (zero time.Time has no defined UnixNano;
// recordstore.SeqTs(0) is the equivalent explicit bound);
// opts.To bounds the replay exclusively ("state as of To") and
// opts.Limit caps the row count. The sequence is single-use; ctx
// must stay valid until iteration completes; the query may execute
// at call time or lazily during iteration (buffered in v1 — a
// streaming executor changes nothing visible); an error ends the
// sequence as a final (nil, err) pair. Reads see only flushed rows.
func (inst *LedgerStore) Replay(ctx context.Context, key string, fromOrder time.Time, opts recordstore.ReplayOpts) iter.Seq2[*LedgerEntity, error] {
	sql := "SELECT * FROM " + LedgerTableName +
		" WHERE " + LedgerColKey + " = " + ledgerKeyLiteral(key)
	if !fromOrder.IsZero() {
		sql += " AND " + LedgerColOrder + " >= fromUnixTimestamp64Nano(" + strconv.FormatInt(fromOrder.UnixNano(), 10) + ")"
	}
	if !opts.To.IsZero() {
		sql += " AND " + LedgerColOrder + " < fromUnixTimestamp64Nano(" + strconv.FormatInt(opts.To.UnixNano(), 10) + ")"
	}
	sql += " ORDER BY " + LedgerColOrder + " ASC"
	if opts.Limit > 0 {
		sql += " LIMIT " + strconv.Itoa(opts.Limit)
	}
	sql += ledgerArrowOutputSettings
	return inst.iterateEntities(ctx, sql)
}

// --- decode (Arrow → entity bags). ---

// ledgerSectionReaderI is the uniform slice of the generated read-access
// readers. Column indices stay at their constructor defaults — the
// schema order a SELECT * returns.
type ledgerSectionReaderI interface {
	LoadFromRecord(raruntime.RecordI) error
	Release()
}

func (inst *LedgerStore) queryEntities(ctx context.Context, sql string) (ents []*LedgerEntity, err error) {
	for rec, rerr := range inst.exec.QueryArrow(ctx, sql) {
		if rerr != nil {
			err = eh.Errorf("query entities: %w", rerr)
			return
		}
		batch, derr := decodeLedgerRecord(rec)
		rec.Release()
		if derr != nil {
			err = derr
			return
		}
		ents = append(ents, batch...)
	}
	return
}

// iterateEntities adapts the buffered query path to the single-use
// iterator contract shared by Replay and the Scan verbs: entities
// yield in query order; an error yields once as (nil, err) and ends
// the sequence.
func (inst *LedgerStore) iterateEntities(ctx context.Context, sql string) iter.Seq2[*LedgerEntity, error] {
	return func(yield func(*LedgerEntity, error) bool) {
		ents, err := inst.queryEntities(ctx, sql)
		if err != nil {
			yield(nil, err)
			return
		}
		for _, ent := range ents {
			if !yield(ent, nil) {
				return
			}
		}
	}
}

// decodeLedgerRecord reads one fetched Arrow record into entity bags:
// envelope from the plain readers, components via presence-gated,
// membership-matched reads (fat rows carry optional components — the
// kind-homogeneous helpers cannot decode them).
func decodeLedgerRecord(rec arrow.RecordBatch) (ents []*LedgerEntity, err error) {
	idR := lowlevel.NewReadAccessLedgerTablePlainEntityIdAttributes()
	tsR := lowlevel.NewReadAccessLedgerTablePlainEntityTimestampAttributes()
	acctOwnerR := lowlevel.NewReadAccessLedgerTableTaggedAcctOwner()
	acctDepositR := lowlevel.NewReadAccessLedgerTableTaggedAcctDeposit()
	acctWithdrawR := lowlevel.NewReadAccessLedgerTableTaggedAcctWithdraw()
	acctClosedR := lowlevel.NewReadAccessLedgerTableTaggedAcctClosed()
	snapOwnerR := lowlevel.NewReadAccessLedgerTableTaggedSnapOwner()
	snapBalanceR := lowlevel.NewReadAccessLedgerTableTaggedSnapBalance()
	snapClosedR := lowlevel.NewReadAccessLedgerTableTaggedSnapClosed()
	snapAsOfR := lowlevel.NewReadAccessLedgerTableTaggedSnapAsOf()
	readers := []ledgerSectionReaderI{idR, tsR, acctOwnerR, acctDepositR, acctWithdrawR, acctClosedR, snapOwnerR, snapBalanceR, snapClosedR, snapAsOfR}
	for _, r := range readers {
		err = r.LoadFromRecord(rec)
		if err != nil {
			err = eh.Errorf("load ledger reader from record: %w", err)
			return
		}
	}
	defer func() {
		for _, r := range readers {
			r.Release()
		}
	}()

	n := idR.ValueId.Len()
	tsType, ok := tsR.ValueTs.DataType().(*arrow.TimestampType)
	if !ok {
		err = eh.Errorf("order column is not a timestamp (got %s)", tsR.ValueTs.DataType())
		return
	}
	ents = make([]*LedgerEntity, 0, n)
	for i := range n {
		ent := &LedgerEntity{
			ID: idR.ValueId.Value(i),
			Ts: tsR.ValueTs.Value(i).ToTime(tsType.Unit).UTC(),
		}
		{
			row, ok, e := openedReadRow(i, acctOwnerR.GetAttributes(), acctOwnerR.GetMemberships())
			if e != nil {
				err = eh.Errorf("read opened component: %w", e)
				return
			}
			if ok {
				row.ID = ent.ID
				ent.Opened = option.Some(row)
			}
		}
		{
			row, ok, e := depositedReadRow(i, acctDepositR.GetAttributes(), acctDepositR.GetMemberships())
			if e != nil {
				err = eh.Errorf("read deposited component: %w", e)
				return
			}
			if ok {
				row.ID = ent.ID
				ent.Deposited = option.Some(row)
			}
		}
		{
			row, ok, e := withdrawnReadRow(i, acctWithdrawR.GetAttributes(), acctWithdrawR.GetMemberships())
			if e != nil {
				err = eh.Errorf("read withdrawn component: %w", e)
				return
			}
			if ok {
				row.ID = ent.ID
				ent.Withdrawn = option.Some(row)
			}
		}
		{
			row, ok, e := closedReadRow(i, acctClosedR.GetAttributes(), acctClosedR.GetMemberships())
			if e != nil {
				err = eh.Errorf("read closed component: %w", e)
				return
			}
			if ok {
				row.ID = ent.ID
				ent.Closed = option.Some(row)
			}
		}
		{
			row, ok, e := accountStateReadRow(i, snapOwnerR.GetAttributes(), snapOwnerR.GetMemberships(), snapBalanceR.GetAttributes(), snapBalanceR.GetMemberships(), snapClosedR.GetAttributes(), snapClosedR.GetMemberships(), snapAsOfR.GetAttributes(), snapAsOfR.GetMemberships())
			if e != nil {
				err = eh.Errorf("read accountState component: %w", e)
				return
			}
			if ok {
				row.ID = ent.ID
				ent.AccountState = option.Some(row)
			}
		}
		ents = append(ents, ent)
	}
	return
}
